{"content": "     1|/**
     2| * @module state
     3| * @description Manage STATE.md — read, parse, update current phase/wave/task statuses,
     4| * log decisions, record blockers, and track metrics.
     5| */
     6|
     7|import { readFile, writeFile } from 'node:fs/promises';
     8|
     9|/**
    10| * @typedef {Object} TaskStatus
    11| * @property {string} id - Task ID (e.g., "SEO-01")
    12| * @property {string} status - planned | dispatched | in_progress | blocked | done | verified
    13| * @property {string} [note] - Optional status note
    14| */
    15|
    16|/**
    17| * @typedef {Object} Decision
    18| * @property {string} date - ISO date string
    19| * @property {string} decision - What was decided
    20| * @property {string} by - Who made the decision
    21| * @property {string} [context] - Why
    22| */
    23|
    24|/**
    25| * @typedef {Object} Blocker
    26| * @property {string} id - Blocker ID
    27| * @property {string} description - What's blocked
    28| * @property {string} [taskId] - Related task
    29| * @property {string} status - active | resolved
    30| * @property {string} [resolution] - How it was resolved
    31| */
    32|
    33|/**
    34| * @typedef {Object} Metrics
    35| * @property {number} tasksTotal
    36| * @property {number} tasksDone
    37| * @property {number} tasksBlocked
    38| * @property {number} tasksInProgress
    39| * @property {string} lastUpdated - ISO timestamp
    40| */
    41|
    42|/**
    43| * @typedef {Object} GSDState
    44| * @property {string} project - Project name
    45| * @property {string} currentPhase - Current phase ID
    46| * @property {number} currentWave - Current wave number
    47| * @property {string} lifecycle - DISCUSS | RESEARCH | PLAN | APPROVE | EXECUTE | VERIFY | SHIP
    48| * @property {Object<string, string>} taskStatuses - taskId → status
    49| * @property {Decision[]} decisions
    50| * @property {Blocker[]} blockers
    51| * @property {Metrics} metrics
    52| */
    53|
    54|// ─── Parser ────────────────────────────────────────────────────────────────────
    55|
    56|/**
    57| * Parse a STATE.md file into a structured state object.
    58| *
    59| * @param {string} filePath - Path to STATE.md
    60| * @returns {Promise<GSDState>}
    61| */
    62|export async function readState(filePath) {
    63|  const content = await readFile(filePath, 'utf-8');
    64|  return parseStateContent(content);
    65|}
    66|
    67|/**
    68| * Parse STATE.md content string into a structured state object.
    69| *
    70| * @param {string} content - Raw STATE.md content
    71| * @returns {GSDState}
    72| */
    73|export function parseStateContent(content) {
    74|  const state = {
    75|    project: '',
    76|    currentPhase: '',
    77|    currentWave: 1,
    78|    lifecycle: 'PLAN',
    79|    taskStatuses: {},
    80|    decisions: [],
    81|    blockers: [],
    82|    metrics: {
    83|      tasksTotal: 0,
    84|      tasksDone: 0,
    85|      tasksBlocked: 0,
    86|      tasksInProgress: 0,
    87|      lastUpdated: '',
    88|    },
    89|  };
    90|
    91|  // Extract YAML frontmatter
    92|  const fmMatch = content.match(/^---\s*\n([\s\S]*?)\n---/);
    93|  if (fmMatch) {
    94|    const yaml = fmMatch[1];
    95|    for (const line of yaml.split('\n')) {
    96|      const kv = line.match(/^([\w_-]+):\s*(.+)$/);
    97|      if (!kv) continue;
    98|      const [, key, val] = kv;
    99|      const v = val.trim().replace(/^["']|["']$/g, '');
   100|      switch (key) {
   101|        case 'project': state.project = v; break;
   102|        case 'phase':
   103|        case 'current_phase':
   104|        case 'currentPhase': state.currentPhase = v; break;
   105|        case 'wave':
   106|        case 'current_wave':
   107|        case 'currentWave': state.currentWave = parseInt(v, 10) || 1; break;
   108|        case 'lifecycle':
   109|        case 'stage': state.lifecycle = v.toUpperCase(); break;
   110|      }
   111|    }
   112|  }
   113|
   114|  // Parse task status table
   115|  // Expected format: | TASK-ID | status | note |
   116|  const tableMatch = content.match(/##\s*Task\s+Status[^\n]*\n([\s\S]*?)(?=\n##\s|$)/i);
   117|  if (tableMatch) {
   118|    const lines = tableMatch[1].split('\n');
   119|    for (const line of lines) {
   120|      if (!line.includes('|') || line.match(/^[\s|:-]+$/)) continue; // skip headers/separators
   121|      const cells = line.split('|').map(c => c.trim()).filter(Boolean);
   122|      if (cells.length >= 2 && !cells[0].toLowerCase().includes('task') && !cells[0].toLowerCase().includes('id')) {
   123|        state.taskStatuses[cells[0]] = cells[1];
   124|      }
   125|    }
   126|  }
   127|
   128|  // Parse decisions
   129|  const decisionsMatch = content.match(/##\s*Decisions[^\n]*\n([\s\S]*?)(?=\n##\s|$)/i);
   130|  if (decisionsMatch) {
   131|    const lines = decisionsMatch[1].split('\n');
   132|    for (const line of lines) {
   133|      const decMatch = line.match(/^[-*]\s*\*?\*?\[?(\d{4}-\d{2}-\d{2})\]?\*?\*?\s*[-–:]\s*(.+?)(?:\s*\(by\s+([^)]+)\))?$/i);
   134|      if (decMatch) {
   135|        state.decisions.push({
   136|          date: decMatch[1],
   137|          decision: decMatch[2].trim(),
   138|          by: decMatch[3] || 'unknown',
   139|        });
   140|      }
   141|    }
   142|  }
   143|
   144|  // Parse blockers
   145|  const blockersMatch = content.match(/##\s*Blockers[^\n]*\n([\s\S]*?)(?=\n##\s|$)/i);
   146|  if (blockersMatch) {
   147|    const lines = blockersMatch[1].split('\n');
   148|    for (const line of lines) {
   149|      const blMatch = line.match(/^[-*]\s*\*?\*?([A-Z]+-\d+)?\*?\*?\s*[-–:]?\s*(.+?)(?:\s*\[(\w+)\])?$/i);
   150|      if (blMatch && blMatch[2]) {
   151|        state.blockers.push({
   152|          id: blMatch[1] || `BLK-${state.blockers.length + 1}`,
   153|          description: blMatch[2].trim(),
   154|          status: (blMatch[3] || 'active').toLowerCase(),
   155|        });
   156|      }
   157|    }
   158|  }
   159|
   160|  // Parse metrics
   161|  const metricsMatch = content.match(/##\s*Metrics[^\n]*\n([\s\S]*?)(?=\n##\s|$)/i);
   162|  if (metricsMatch) {
   163|    const block = metricsMatch[1];
   164|    const totalM = block.match(/total[:\s]*(\d+)/i);
   165|    const doneM = block.match(/done[:\s]*(\d+)/i);
   166|    const blockedM = block.match(/blocked[:\s]*(\d+)/i);
   167|    const progressM = block.match(/in.progress[:\s]*(\d+)/i);
   168|    const updatedM = block.match(/updated[:\s]*(.+)/i);
   169|
   170|    if (totalM) state.metrics.tasksTotal = parseInt(totalM[1], 10);
   171|    if (doneM) state.metrics.tasksDone = parseInt(doneM[1], 10);
   172|    if (blockedM) state.metrics.tasksBlocked = parseInt(blockedM[1], 10);
   173|    if (progressM) state.metrics.tasksInProgress = parseInt(progressM[1], 10);
   174|    if (updatedM) state.metrics.lastUpdated = updatedM[1].trim();
   175|  }
   176|
   177|  // Recompute metrics from task statuses if available
   178|  const statuses = Object.values(state.taskStatuses);
   179|  if (statuses.length > 0) {
   180|    state.metrics.tasksTotal = statuses.length;
   181|    state.metrics.tasksDone = statuses.filter(s => s === 'done' || s === 'verified').length;
   182|    state.metrics.tasksBlocked = statuses.filter(s => s === 'blocked').length;
   183|    state.metrics.tasksInProgress = statuses.filter(s => s === 'in_progress' || s === 'dispatched').length;
   184|  }
   185|
   186|  return state;
   187|}
   188|
   189|// ─── Serializer ────────────────────────────────────────────────────────────────
   190|
   191|/**
   192| * Serialize a GSDState object back to STATE.md format.
   193| *
   194| * @param {GSDState} state
   195| * @returns {string} STATE.md content
   196| */
   197|export function serializeState(state) {
   198|  const now = new Date().toISOString();
   199|  state.metrics.lastUpdated = now;
   200|
   201|  const lines = [];
   202|
   203|  // Frontmatter
   204|  lines.push('---');
   205|  lines.push(`project: ${state.project}`);
   206|  lines.push(`current_phase: ${state.currentPhase}`);
   207|  lines.push(`current_wave: ${state.currentWave}`);
   208|  lines.push(`lifecycle: ${state.lifecycle}`);
   209|  lines.push(`updated: ${now}`);
   210|  lines.push('---');
   211|  lines.push('');
   212|
   213|  // Title
   214|  lines.push(`# State: ${state.project}`);
   215|  lines.push('');
   216|
   217|  // Current position
   218|  lines.push('## Current Position');
   219|  lines.push(`- **Phase:** ${state.currentPhase}`);
   220|  lines.push(`- **Wave:** ${state.currentWave}`);
   221|  lines.push(`- **Lifecycle:** ${state.lifecycle}`);
   222|  lines.push('');
   223|
   224|  // Task Status Table
   225|  lines.push('## Task Status');
   226|  lines.push('');
   227|  lines.push('| Task ID | Status |');
   228|  lines.push('|---------|--------|');
   229|  for (const [id, status] of Object.entries(state.taskStatuses)) {
   230|    lines.push(`| ${id} | ${status} |`);
   231|  }
   232|  lines.push('');
   233|
   234|  // Decisions
   235|  lines.push('## Decisions');
   236|  lines.push('');
   237|  if (state.decisions.length === 0) {
   238|    lines.push('_No decisions recorded yet._');
   239|  } else {
   240|    for (const d of state.decisions) {
   241|      lines.push(`- **${d.date}** — ${d.decision}${d.by ? ` (by ${d.by})` : ''}`);
   242|    }
   243|  }
   244|  lines.push('');
   245|
   246|  // Blockers
   247|  lines.push('## Blockers');
   248|  lines.push('');
   249|  const activeBlockers = state.blockers.filter(b => b.status === 'active');
   250|  if (activeBlockers.length === 0) {
   251|    lines.push('_No active blockers._');
   252|  } else {
   253|    for (const b of activeBlockers) {
   254|      lines.push(`- **${b.id}** — ${b.description} [${b.status}]`);
   255|    }
   256|  }
   257|  lines.push('');
   258|
   259|  // Metrics
   260|  lines.push('## Metrics');
   261|  lines.push('');
   262|  lines.push(`- Total: ${state.metrics.tasksTotal}`);
   263|  lines.push(`- Done: ${state.metrics.tasksDone}`);
   264|  lines.push(`- In Progress: ${state.metrics.tasksInProgress}`);
   265|  lines.push(`- Blocked: ${state.metrics.tasksBlocked}`);
   266|  lines.push(`- Last Updated: ${state.metrics.lastUpdated}`);
   267|  lines.push('');
   268|
   269|  return lines.join('\n');
   270|}
   271|
   272|// ─── Update Operations ─────────────────────────────────────────────────────────
   273|
   274|/**
   275| * Update the current phase and wave.
   276| *
   277| * @param {GSDState} state
   278| * @param {string} phase - New phase ID
   279| * @param {number} wave - New wave number
   280| * @returns {GSDState} Updated state (mutated in place)
   281| */
   282|export function setPhaseAndWave(state, phase, wave) {
   283|  state.currentPhase = phase;
   284|  state.currentWave = wave;
   285|  return state;
   286|}
   287|
   288|/**
   289| * Update the lifecycle stage.
   290| *
   291| * @param {GSDState} state
   292| * @param {string} lifecycle - DISCUSS | RESEARCH | PLAN | APPROVE | EXECUTE | VERIFY | SHIP
   293| * @returns {GSDState}
   294| */
   295|export function setLifecycle(state, lifecycle) {
   296|  state.lifecycle = lifecycle.toUpperCase();
   297|  return state;
   298|}
   299|
   300|/**
   301| * Update a single task's status.
   302| *
   303| * @param {GSDState} state
   304| * @param {string} taskId - Task ID (e.g., "SEO-01")
   305| * @param {string} status - New status
   306| * @returns {GSDState}
   307| */
   308|export function setTaskStatus(state, taskId, status) {
   309|  state.taskStatuses[taskId] = status;
   310|  recomputeMetrics(state);
   311|  return state;
   312|}
   313|
   314|/**
   315| * Bulk update task statuses.
   316| *
   317| * @param {GSDState} state
   318| * @param {Object<string, string>} updates - taskId → new status
   319| * @returns {GSDState}
   320| */
   321|export function setTaskStatuses(state, updates) {
   322|  for (const [id, status] of Object.entries(updates)) {
   323|    state.taskStatuses[id] = status;
   324|  }
   325|  recomputeMetrics(state);
   326|  return state;
   327|}
   328|
   329|/**
   330| * Log a decision.
   331| *
   332| * @param {GSDState} state
   333| * @param {string} decision - What was decided
   334| * @param {string} [by='hermes'] - Who decided
   335| * @param {string} [context] - Why
   336| * @returns {GSDState}
   337| */
   338|export function logDecision(state, decision, by = 'hermes', context) {
   339|  state.decisions.push({
   340|    date: new Date().toISOString().split('T')[0],
   341|    decision,
   342|    by,
   343|    context,
   344|  });
   345|  return state;
   346|}
   347|
   348|/**
   349| * Add a blocker.
   350| *
   351| * @param {GSDState} state
   352| * @param {string} description - What's blocked
   353| * @param {string} [taskId] - Related task ID
   354| * @returns {GSDState}
   355| */
   356|export function addBlocker(state, description, taskId) {
   357|  const id = `BLK-${String(state.blockers.length + 1).padStart(3, '0')}`;
   358|  state.blockers.push({
   359|    id,
   360|    description,
   361|    taskId,
   362|    status: 'active',
   363|  });
   364|  return state;
   365|}
   366|
   367|/**
   368| * Resolve a blocker.
   369| *
   370| * @param {GSDState} state
   371| * @param {string} blockerId - Blocker ID
   372| * @param {string} resolution - How it was resolved
   373| * @returns {GSDState}
   374| */
   375|export function resolveBlocker(state, blockerId, resolution) {
   376|  const blocker = state.blockers.find(b => b.id === blockerId);
   377|  if (blocker) {
   378|    blocker.status = 'resolved';
   379|    blocker.resolution = resolution;
   380|  }
   381|  return state;
   382|}
   383|
   384|/**
   385| * Recompute metrics from current task statuses.
   386| *
   387| * @param {GSDState} state
   388| * @returns {GSDState}
   389| */
   390|export function recomputeMetrics(state) {
   391|  const statuses = Object.values(state.taskStatuses);
   392|  state.metrics.tasksTotal = statuses.length;
   393|  state.metrics.tasksDone = statuses.filter(s => s === 'done' || s === 'verified').length;
   394|  state.metrics.tasksBlocked = statuses.filter(s => s === 'blocked').length;
   395|  state.metrics.tasksInProgress = statuses.filter(s => s === 'in_progress' || s === 'dispatched').length;
   396|  state.metrics.lastUpdated = new Date().toISOString();
   397|  return state;
   398|}
   399|
   400|// ─── File I/O ──────────────────────────────────────────────────────────────────
   401|
   402|/**
   403| * Write state to a STATE.md file.
   404| *
   405| * @param {string} filePath - Path to STATE.md
   406| * @param {GSDState} state - State object to write
   407| * @returns {Promise<void>}
   408| */
   409|export async function writeState(filePath, state) {
   410|  const content = serializeState(state);
   411|  await writeFile(filePath, content, 'utf-8');
   412|}
   413|
   414|/**
   415| * Read, update, and write back STATE.md atomically.
   416| *
   417| * @param {string} filePath - Path to STATE.md
   418| * @param {(state: GSDState) => GSDState} updater - Function that mutates state
   419| * @returns {Promise<GSDState>} The updated state
   420| */
   421|export async function updateState(filePath, updater) {
   422|  let state;
   423|  try {
   424|    state = await readState(filePath);
   425|  } catch (err) {
   426|    if (err.code === 'ENOENT') {
   427|      // Initialize empty state
   428|      state = createEmptyState();
   429|    } else {
   430|      throw err;
   431|    }
   432|  }
   433|
   434|  updater(state);
   435|  await writeState(filePath, state);
   436|  return state;
   437|}
   438|
   439|/**
   440| * Create an empty state object.
   441| *
   442| * @param {string} [project=''] - Project name
   443| * @returns {GSDState}
   444| */
   445|export function createEmptyState(project = '') {
   446|  return {
   447|    project,
   448|    currentPhase: '',
   449|    currentWave: 1,
   450|    lifecycle: 'PLAN',
   451|    taskStatuses: {},
   452|    decisions: [],
   453|    blockers: [],
   454|    metrics: {
   455|      tasksTotal: 0,
   456|      tasksDone: 0,
   457|      tasksBlocked: 0,
   458|      tasksInProgress: 0,
   459|      lastUpdated: new Date().toISOString(),
   460|    },
   461|  };
   462|}
   463|
   464|/**
   465| * Initialize task statuses from a parsed plan.
   466| * Sets all tasks to "planned" unless they already have a status.
   467| *
   468| * @param {GSDState} state
   469| * @param {import('./parser.js').Task[]} tasks
   470| * @returns {GSDState}
   471| */
   472|export function initTaskStatuses(state, tasks) {
   473|  for (const task of tasks) {
   474|    if (!state.taskStatuses[task.id]) {
   475|      state.taskStatuses[task.id] = 'planned';
   476|    }
   477|  }
   478|  recomputeMetrics(state);
   479|  return state;
   480|}
   481|
   482|/**
   483| * Check if all tasks in the current wave are complete.
   484| *
   485| * @param {GSDState} state
   486| * @param {import('./parser.js').Task[]} tasks - All tasks
   487| * @returns {boolean}
   488| */
   489|export function isWaveComplete(state, tasks) {
   490|  const waveTasks = tasks.filter(t => t.wave === state.currentWave || t.wave === String(state.currentWave));
   491|  return waveTasks.every(t => {
   492|    const status = state.taskStatuses[t.id];
   493|    return status === 'done' || status === 'verified';
   494|  });
   495|}
