{"content": "     1|/**
     2| * @module parser
     3| * @description Parse PLAN.md files — extract YAML frontmatter and XML task definitions
     4| * into structured objects for the GSD execution engine.
     5| */
     6|
     7|import { readFile, readdir } from 'node:fs/promises';
     8|import { join, basename } from 'node:path';
     9|
    10|/**
    11| * @typedef {Object} TaskMeta
    12| * @property {string} phase
    13| * @property {string} title
    14| * @property {string} goal
    15| * @property {string} status
    16| * @property {string} approval
    17| * @property {number|string} wave
    18| */
    19|
    20|/**
    21| * @typedef {Object} Task
    22| * @property {string} id
    23| * @property {string} type
    24| * @property {string} assignee
    25| * @property {string|number} wave
    26| * @property {string} title
    27| * @property {string} description
    28| * @property {string|null} approval
    29| * @property {string} verify
    30| * @property {string} done
    31| */
    32|
    33|/**
    34| * @typedef {Object} ParsedPlan
    35| * @property {TaskMeta} meta
    36| * @property {string[]} mustBeTrue
    37| * @property {Task[]} tasks
    38| */
    39|
    40|/**
    41| * Parse YAML frontmatter from a markdown string.
    42| * Expects content between opening and closing --- markers.
    43| *
    44| * @param {string} content - Raw markdown content
    45| * @returns {TaskMeta} Parsed frontmatter fields
    46| */
    47|export function parseFrontmatter(content) {
    48|  const match = content.match(/^---\s*\n([\s\S]*?)\n---/);
    49|  if (!match) {
    50|    return { phase: '', title: '', goal: '', status: 'planned', approval: 'none', wave: 1 };
    51|  }
    52|
    53|  const yaml = match[1];
    54|  const meta = {};
    55|
    56|  for (const line of yaml.split('\n')) {
    57|    const kvMatch = line.match(/^(\w[\w-]*):\s*(.+)$/);
    58|    if (kvMatch) {
    59|      const key = kvMatch[1].trim();
    60|      let value = kvMatch[2].trim();
    61|      // Strip surrounding quotes
    62|      if ((value.startsWith('"') && value.endsWith('"')) ||
    63|          (value.startsWith("'") && value.endsWith("'"))) {
    64|        value = value.slice(1, -1);
    65|      }
    66|      // Strip inline comments
    67|      value = value.replace(/\s+#\s+.*$/, '');
    68|      // Coerce numbers
    69|      if (/^\d+$/.test(value)) value = parseInt(value, 10);
    70|      meta[key] = value;
    71|    }
    72|  }
    73|
    74|  return {
    75|    phase: meta.phase ?? '',
    76|    title: meta.title ?? '',
    77|    goal: meta.goal ?? '',
    78|    status: meta.status ?? 'planned',
    79|    approval: meta.approval ?? 'none',
    80|    wave: meta.wave ?? 1,
    81|  };
    82|}
    83|
    84|/**
    85| * Extract "Must Be True" items from the markdown.
    86| * Looks for the section header and collects bullet items.
    87| *
    88| * @param {string} content - Raw markdown content
    89| * @returns {string[]} List of must-be-true conditions
    90| */
    91|export function parseMustBeTrue(content) {
    92|  const sectionMatch = content.match(/##\s*Must\s+Be\s+True[^\n]*\n([\s\S]*?)(?=\n##\s|\n<task\s|$)/i);
    93|  if (!sectionMatch) return [];
    94|
    95|  return sectionMatch[1]
    96|    .split('\n')
    97|    .map(line => line.replace(/^[\s-]*/, '').trim())
    98|    .filter(line => line.length > 0);
    99|}
   100|
   101|/**
   102| * Extract the text content of an XML element from a string.
   103| *
   104| * @param {string} xml - XML fragment
   105| * @param {string} tag - Tag name to extract
